// sieve generates a boolean slice where sieve[i] is true if i is a prime number.
func sieve(max int) []bool {
	sieve := make([]bool, max+1)
	sieve[0] = sieve[1] = false
	for i := 2; i <= max; i++ {
		sieve[i] = true
	}
	for i := 2; i*i <= max; i++ {
		if sieve[i] {
			for j := i * i; j <= max; j += i {
				sieve[j] = false
			}
		}
	}
	return sieve
}

